export function getSourceContracts() {
  return sourceContracts.map(contract => ({
    ...contract,
    actions: (contract.actions || []).map(action => ({ ...action })),
  }))
}

export function getSourceContractsByIds(sourceIds) {
  const wanted = new Set(sourceIds || [])
  return getSourceContracts().filter(contract => wanted.has(contract.sourceId))
}

export function getSourceConnectors() {
  return sourceConnectors.map(connector => ({ ...connector }))
}

export function getSystemServiceAreas() {
  return [...FOUNDATION_SYSTEM_SERVICE_AREAS]
}

export function getGroupedSourceSystems() {
  return groupedSourceSystems.map(system => ({
    ...system,
    sourceIds: [...(system.sourceIds || [])],
    sourceOfTruthIds: [...(system.sourceOfTruthIds || [])],
    supportingSourceIds: [...(system.supportingSourceIds || [])],
    connectorIds: [...(system.connectorIds || [])],
    runtimeJobKeys: [...(system.runtimeJobKeys || [])],
    backlogIds: [...(system.backlogIds || [])],
    appliesTo: [...(system.appliesTo || [])],
    secondaryServiceAreas: [...(system.secondaryServiceAreas || [])],
    actions: (system.actions || []).map(action => ({ ...action })),
  }))
}
